mapper.select:
SELECT i.ord_code, DATE_FORMAT(i.ord_date, '%Y-%m-%d') AS och_date, i.ord_su, i.ord_amnt, i.ord_danw, i.ord_danj, p.prod_name, p.prod_no, p.prod_gyu, p.prod_jai, p.tech_no, p.corp_name, IFNULL(SUM(c.och_su), 0) AS chulgo_su, (i.ord_su - IFNULL(SUM(c.och_su), 0)) AS jan_su FROM tb_ipgo i LEFT JOIN tb_product p ON p.prod_code = i.prod_code LEFT JOIN tb_chulgo c ON c.ord_code = i.ord_code WHERE 1=1
AND DATE(i.ord_date) >= #{sdate}
AND DATE(i.ord_date) <= #{edate}
AND p.corp_name LIKE CONCAT('%', #{corp_name}, '%')
AND p.prod_name LIKE CONCAT('%', #{prod_name}, '%')
GROUP BY i.ord_code, i.ord_date, i.ord_su, i.ord_amnt, i.ord_danw, i.ord_danj, p.prod_name, p.prod_no, p.prod_gyu, p.prod_jai, p.tech_no, p.corp_name ORDER BY i.ord_date DESC
